def sort_list(head):
    if not head or not head.next:
        return head
    slow, fast = head, head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
    mid = slow.next
    slow.next = None  # Split the list
    left = sort_list(head)
    right = sort_list(mid)
    return merge_lists(left, right)

def merge_lists(l1, l2):
